phase1.code:
#include <iostream>

int main() {
    int choice;

    std::cout << "=== Adventure Menu ===" << std::endl;
    std::cout << "1. Explore the forest" << std::endl;
    std::cout << "2. Enter the dungeon" << std::endl;
    std::cout << "3. Rest at the inn" << std::endl;
    std::cout << "4. View inventory" << std::endl;
    std::cout << "Enter your choice: ";
    std::cin >> choice;

    // Switch statement for menu handling
    switch (choice) {
        case 1:
            std::cout << "You venture into the dark forest..." << std::endl;
            break;
        case 2:
            std::cout << "You descend into the dungeon..." << std::endl;
            break;
        case 3:
            std::cout << "You rest and recover health." << std::endl;
            break;
        case 4:
            std::cout << "Inventory: Sword, Shield, 3 Potions" << std::endl;
            break;
        default:
            std::cout << "Invalid choice! Stay here." << std::endl;
            break;
    }

    // Multiple cases sharing the same code
    std::cout << "\n=== Difficulty ===" << std::endl;
    std::cout << "1. Easy" << std::endl;
    std::cout << "2. Medium" << std::endl;
    std::cout << "3. Hard" << std::endl;
    std::cout << "4. Nightmare" << std::endl;
    std::cout << "Choose difficulty: ";
    std::cin >> choice;

    switch (choice) {
        case 1:
            std::cout << "Easy mode. Enemies are weak." << std::endl;
            break;
        case 2:
            std::cout << "Medium mode. Balanced challenge." << std::endl;
            break;
        case 3:
            std::cout << "Hard mode. Good luck." << std::endl;
            break;
        case 4:
            std::cout << "Nightmare mode. You're insane." << std::endl;
            break;
        default:
            std::cout << "Invalid difficulty. Defaulting to Medium." << std::endl;
            break;
    }

    return 0;
}

