    std::cout << "3. Bow" << std::endl;
    std::cout << "Enter your choice: ";
    std::cin >> choice;

    switch (choice) {
        case 1:
            std::cout << "You swing the sword!" << std::endl;
            break;
        case 2:
            std::cout << "You cleave with the axe!" << std::endl;
            break;
        case 3:
            std::cout << "You loose an arrow!" << std::endl;
